// SovaParserInit initializes any static state used to implement SovaParser. By default the
// static state used to implement the parser is lazily initialized during the first call to
// NewSovaParser(). You can call this function if you wish to initialize the static state ahead
// of time.
func SovaParserInit() {
	staticData := &SovaParserStaticData
	staticData.once.Do(sovaParserInit)
}

// NewSovaParser produces a new parser instance for the optional input antlr.TokenStream.
func NewSovaParser(input antlr.TokenStream) *SovaParser {
	SovaParserInit()
	this := new(SovaParser)
	this.BaseParser = antlr.NewBaseParser(input)
	staticData := &SovaParserStaticData
	this.Interpreter = antlr.NewParserATNSimulator(this, staticData.atn, staticData.decisionToDFA, staticData.PredictionContextCache)
	this.RuleNames = staticData.RuleNames
	this.LiteralNames = staticData.LiteralNames
	this.SymbolicNames = staticData.SymbolicNames
	this.GrammarFileName = "Sova.g4"

	return this
}

